use std::collections::HashMap;

#[derive(Debug, Clone)]
enum Token {
    Number(f64),
    Plus,
    Minus,
    Star,
    Slash,
    LParen,
    RParen,
    Equals,
    Let,
    Ident(String),
}

fn tokenize(input: &str) -> Result<Vec<Token>, String> {
    let mut tokens = Vec::new();
    let chars: Vec<char> = input.chars().collect();
    let mut i = 0;

    while i < chars.len() {
        match chars[i] {
            ' ' | '\t' => i += 1,
            '+' => { tokens.push(Token::Plus); i += 1; }
            '-' => { tokens.push(Token::Minus); i += 1; }
            '*' => { tokens.push(Token::Star); i += 1; }
            '/' => { tokens.push(Token::Slash); i += 1; }
            '(' => { tokens.push(Token::LParen); i += 1; }
            ')' => { tokens.push(Token::RParen); i += 1; }
            '=' => { tokens.push(Token::Equals); i += 1; }
            c if c.is_ascii_digit() || c == '.' => {
                let start = i;
                while i < chars.len() && (chars[i].is_ascii_digit() || chars[i] == '.') {
                    i += 1;
                }
                let num_str: String = chars[start..i].iter().collect();
                let num: f64 = num_str.parse()
                    .map_err(|_| format!("Invalid number: {}", num_str))?;
                tokens.push(Token::Number(num));
            }
            c if c.is_ascii_alphabetic() || c == '_' => {
                let start = i;
                while i < chars.len() && (chars[i].is_ascii_alphanumeric() || chars[i] == '_') {
                    i += 1;
                }
                let word: String = chars[start..i].iter().collect();
                if word == "let" {
                    tokens.push(Token::Let);
                } else {
                    tokens.push(Token::Ident(word));
                }
            }
            c => return Err(format!("Unexpected character: {}", c)),
        }
    }
    Ok(tokens)
}

struct Parser {
    tokens: Vec<Token>,
    pos: usize,
}

impl Parser {
    fn new(tokens: Vec<Token>) -> Self {
        Parser { tokens, pos: 0 }
    }

    fn peek(&self) -> Option<&Token> {
        self.tokens.get(self.pos)
    }

    fn advance(&mut self) -> Option<Token> {
        let tok = self.tokens.get(self.pos).cloned();
        self.pos += 1;
        tok
    }

    fn parse_expression(&mut self) -> Result<f64, String> {
        let mut left = self.parse_term()?;
        loop {
            match self.peek() {
                Some(Token::Plus) => { self.advance(); left += self.parse_term()?; }
                Some(Token::Minus) => { self.advance(); left -= self.parse_term()?; }
                _ => break,
            }
        }
        Ok(left)
    }

    fn parse_term(&mut self) -> Result<f64, String> {
        let mut left = self.parse_unary()?;
        loop {
            match self.peek() {
                Some(Token::Star) => { self.advance(); left *= self.parse_unary()?; }
                Some(Token::Slash) => {
                    self.advance();
                    let right = self.parse_unary()?;
                    if right == 0.0 {
                        return Err("Division by zero".to_string());
                    }
                    left /= right;
                }
                _ => break,
            }
        }
        Ok(left)
    }

    fn parse_unary(&mut self) -> Result<f64, String> {
        if let Some(Token::Minus) = self.peek() {
            self.advance();
            let val = self.parse_primary()?;
            return Ok(-val);
        }
        self.parse_primary()
    }

    fn parse_primary(&mut self) -> Result<f64, String> {
        match self.advance() {
            Some(Token::Number(n)) => Ok(n),
            Some(Token::LParen) => {
                let val = self.parse_expression()?;
                match self.advance() {
                    Some(Token::RParen) => Ok(val),
                    _ => Err("Expected closing parenthesis".to_string()),
                }
            }
            Some(Token::Ident(_)) => {
                Err("Variable lookup handled in evaluate()".to_string())
            }
            _ => Err("Expected number or parenthesized expression".to_string()),
        }
    }
}

fn substitute_vars(tokens: &[Token], vars: &HashMap<String, f64>) -> Result<Vec<Token>, String> {
    tokens.iter().map(|tok| {
        match tok {
            Token::Ident(name) => {
                vars.get(name)
                    .map(|&val| Token::Number(val))
                    .ok_or_else(|| format!("Unknown variable: {}", name))
            }
            other => Ok(other.clone()),
        }
    }).collect()
}

fn evaluate(tokens: &[Token], vars: &mut HashMap<String, f64>) -> Result<f64, String> {
    // Handle let assignment: let x = expr
    if tokens.len() >= 3 {
        if let Token::Let = &tokens[0] {
            if let Token::Ident(name) = &tokens[1] {
                if let Token::Equals = &tokens[2] {
                    let expr_tokens = &tokens[3..];
                    let resolved = substitute_vars(expr_tokens, vars)?;
                    let mut parser = Parser::new(resolved);
                    let value = parser.parse_expression()?;
                    vars.insert(name.clone(), value);
                    return Ok(value);
                }
            }
        }
    }

    let resolved = substitute_vars(tokens, vars)?;
    let mut parser = Parser::new(resolved);
    parser.parse_expression()
}

fn main() {
    let mut vars = HashMap::new();
    let inputs = vec![
        "2 + 3 * 4",
        "(2 + 3) * 4",
        "let x = 10",
        "x * 2 + 5",
    ];
    for input in inputs {
        print!("> {}", input);
        match tokenize(input).and_then(|tokens| evaluate(&tokens, &mut vars)) {
            Ok(result) => println!(" = {}", result),
            Err(e) => println!(" Error: {}", e),
        }
    }
}
